import{b as e,J as l,g as a,j as d}from"./chunks/framework.DVAsBjJ_.js";const h=JSON.parse('{"title":"차수 타입 설정","description":"","frontmatter":{},"headers":[],"relativePath":"project/types.md","filePath":"project/types.md","lastUpdated":1780671931000}'),n={name:"project/types.md"};function r(i,t,s,g,x,y){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="차수-타입-설정" tabindex="-1">차수 타입 설정 <a class="header-anchor" href="#차수-타입-설정" aria-label="Permalink to &quot;차수 타입 설정&quot;">​</a></h1><p>프로젝트의 계약 차수, 세부 타입(평형), 그리고 분양가 차등 적용을 위한 층별 범위를 관리합니다.</p><h2 id="차수-분류-등록" tabindex="-1">차수 분류 등록 <a class="header-anchor" href="#차수-분류-등록" aria-label="Permalink to &quot;차수 분류 등록&quot;">​</a></h2><p>프로젝트의 계약 진행 단계에 따른 차수 그룹을 등록합니다. 이 정보는 계약 등록 및 분양가 산정 시 기준으로 활용됩니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 설정 &gt; 차수 타입 설정 &gt; 차수 분류 등록</code></li></ul><h4 id="주요-입력-항목" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">등록차수</td><td style="text-align:center;">필수</td><td style="text-align:left;">해당 차수의 순서(회차)를 숫자로 입력</td></tr><tr><td style="text-align:left;">차수구분</td><td style="text-align:center;">필수</td><td style="text-align:left;">조합모집 또는 일반분양 중 선택</td></tr><tr><td style="text-align:left;">차수그룹명</td><td style="text-align:center;">필수</td><td style="text-align:left;">차수를 식별할 수 있는 명칭 (예: 1차 조합원, 일반분양분 등)</td></tr><tr><td style="text-align:left;">미계약세대 기본설정</td><td style="text-align:center;"></td><td style="text-align:left;">미계약 세대 공급가격 생성 시 기본 적용 차수 (프로젝트당 1개만 설정 가능)</td></tr></tbody></table><h2 id="타입-정보-등록" tabindex="-1">타입 정보 등록 <a class="header-anchor" href="#타입-정보-등록" aria-label="Permalink to &quot;타입 정보 등록&quot;">​</a></h2><p>공급 시설의 타입(평형)별 세부 정보를 등록하고 면적 및 가격 설정 방식을 정의합니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 설정 &gt; 차수 타입 설정 &gt; 타입 정보 등록</code></li></ul><h4 id="주요-입력-항목-1" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목-1" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">타입종류</td><td style="text-align:center;">필수</td><td style="text-align:left;">공동주택, 오피스텔, 숙박시설 등 시설 용도 선택</td></tr><tr><td style="text-align:left;">타입구분</td><td style="text-align:center;">필수</td><td style="text-align:left;">메인유닛 또는 보조시설 여부 선택</td></tr><tr><td style="text-align:left;">타입명칭</td><td style="text-align:center;">필수</td><td style="text-align:left;">타입을 식별하는 명칭 (예: 84A, 59B 등)</td></tr><tr><td style="text-align:left;">타입색상</td><td style="text-align:center;">필수</td><td style="text-align:left;">현황판 등에서 타입을 구분하기 위한 전용 색상 지정</td></tr><tr><td style="text-align:left;">전용면적</td><td style="text-align:center;"></td><td style="text-align:left;">전용면적 (제곱미터)</td></tr><tr><td style="text-align:left;">공급면적</td><td style="text-align:center;"></td><td style="text-align:left;">공급면적 (제곱미터)</td></tr><tr><td style="text-align:left;">계약면적</td><td style="text-align:center;"></td><td style="text-align:left;">계약면적 (제곱미터)</td></tr><tr><td style="text-align:left;">평균가격</td><td style="text-align:center;"></td><td style="text-align:left;">해당 타입의 기준 평균 분양가격</td></tr><tr><td style="text-align:left;">공급가 설정 옵션</td><td style="text-align:center;">필수</td><td style="text-align:left;">가격 책정 기준 (타입별 / 층타입별 / 호별 설정 중 선택)</td></tr><tr><td style="text-align:left;">세대수</td><td style="text-align:center;">필수</td><td style="text-align:left;">해당 타입으로 공급되는 총 세대수</td></tr></tbody></table><h2 id="층별-조건-등록" tabindex="-1">층별 조건 등록 <a class="header-anchor" href="#층별-조건-등록" aria-label="Permalink to &quot;층별 조건 등록&quot;">​</a></h2><p>층별로 분양가를 다르게 적용(층별 차등가)하기 위한 층 범위를 설정합니다. 이 설정은 타입 정보 등록에서 &#39;층타입별 설정&#39;을 선택한 경우에 적용됩니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 설정 &gt; 차수 타입 설정 &gt; 층별 조건 등록</code></li></ul><h4 id="주요-입력-항목-2" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목-2" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">타입종류</td><td style="text-align:center;">필수</td><td style="text-align:left;">층 조건을 적용할 시설 용도 선택</td></tr><tr><td style="text-align:left;">시작 층</td><td style="text-align:center;">필수</td><td style="text-align:left;">범위의 시작 층 (지하층은 -1 이하 숫자로 입력)</td></tr><tr><td style="text-align:left;">종료 층</td><td style="text-align:center;">필수</td><td style="text-align:left;">범위의 종료 층</td></tr><tr><td style="text-align:left;">방향/위치(옵션)</td><td style="text-align:center;"></td><td style="text-align:left;">향(동/서/남/북)이나 라인 등 추가 구분 조건 입력</td></tr><tr><td style="text-align:left;">층별 범위 명칭</td><td style="text-align:center;">필수</td><td style="text-align:left;">해당 범위를 식별할 명칭 (예: 1~3층, 저층부, 기준층 등)</td></tr></tbody></table>',17)])])}const f=e(n,[["render",r]]);export{h as __pageData,f as default};
